Physical Examinations: {'Vital_Signs': {'Pulse': '82/min', 'Blood_Pressure': '170/92 mm Hg'}, 'Neurovascular_Examination': {'Straight_Leg_Raise_Test': 'Induces pallor and tingling pain in the right foot, without back pain', 'Muscle_Strength': 'Normal throughout', 'Pulses': 'Femoral pulses palpable, right pedal pulses absent'}}
Test Results: {'Blood_Glucose': {'Fasting_Blood_Glucose': 'Elevated'}, 'Ankle-Brachial_Index': {'Right': 'Reduced, indicative of peripheral artery disease'}, 'Doppler_Ultrasound_Right_Lower_Extremity': {'Findings': 'Reduced blood flow and stenosis in the femoropopliteal artery segment'}}

